export default function Timeline({ onNext }: { onNext: () => void }) {
  const startDate = new Date("2025-04-08T03:20:00");

  const [time, setTime] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0,
  });

  useEffect(() => {
    const interval = setInterval(() => {
      const now = new Date().getTime();
      const diff = now - startDate.getTime();
      const days = Math.floor(diff / (1000 * 60 * 60 * 24));
      const hours = Math.floor((diff / (1000 * 60 * 60)) % 24);
      const minutes = Math.floor((diff / (1000 * 60)) % 60);
      const seconds = Math.floor((diff / 1000) % 60);
      setTime({ days, hours, minutes, seconds });
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  return (
    <section style={styles.wrap}>
      <div style={styles.left}>
        <h2 style={styles.h2}>Linha do tempo</h2>

        <p style={styles.p}>Clica em cada etapa</p>

        <div className="minimalScroll" style={styles.list}>
          {events.map((e, idx) => (
            <details key={idx} style={styles.item}>
              <summary style={styles.summary}>
                <span style={styles.index}>
                  {String(idx + 1).padStart(2, "0")}
                </span>
                <span style={styles.title}>{e.title}</span>
              </summary>
              <div className="minimalScroll" style={styles.body}>
                {e.desc}
              </div>
            </details>
          ))}
        </div>

        <div style={styles.counter}>
          <div style={styles.counterTitle}>Desde 08/04/25, 03h20</div>

          <div style={styles.counterGrid}>
            <div>
              <div style={styles.counterNumber}>{time.days}</div>
              <div style={styles.counterLabel}>dias</div>
            </div>

            <div>
              <div style={styles.counterNumber}>{time.hours}</div>
              <div style={styles.counterLabel}>horas</div>
            </div>

            <div>
              <div style={styles.counterNumber}>{time.minutes}</div>
              <div style={styles.counterLabel}>min</div>
            </div>

            <div>
              <div style={styles.counterNumber}>{time.seconds}</div>
              <div style={styles.counterLabel}>seg</div>
            </div>
          </div>
        </div>

        <button onClick={onNext} style={styles.primary}>
          Próximo: Fotos →
        </button>
      </div>

      <div style={styles.right}>
        <div style={styles.note}>
          <img
            src="/photos/961a830d-4167-47d5-b31e-229310f98297.jpeg"
            alt="Momento especial"
            style={styles.noteImage}
          />
        </div>

        <div style={styles.panel}>
          <div style={styles.panelTitle}>Pontuações</div>

          <ul className="minimalScroll" style={styles.ul}>
            <li>
              1. Sabe que eu dou muito valor as suas palavras? Tudo eu dou, mas
              palavras quando vêm de você mexem de uma forma diferente. E eu não
              tô falando de elogios.
            </li>

            <li>
              2. Sabe o campo de 10 hectares que eu falei que teríamos? Então,
              muito mais do que um sonho, é uma promessa que eu tenho.
            </li>

            <li>
              3. Lembra o nosso primeiro check-out? Que você não tinha ideia do
              que seria, peguei uma cadeira na mesa e não passava nem uma agulha
              em você, já que não sabia o que seria. Foi o check-out que
              passamos mais tempo, apesar do mais incompleto.
            </li>

            <li>
              4. Quando te pedi seu What Asap pela primeira vez, o que você
              pensou? Nunca te fiz essa pergunta.
            </li>
          </ul>
        </div>
      </div>
    </section>
  );
}

